import Navbar from "../../components/navbar";
import profil from "../../assets/profil.png";

const About = () => {
    const dataChecks = [
        { id: 1, title: "UI/UX Design" },
        { id: 2, title: "Front-End Web Development" },
        { id: 3, title: "Back-End Web Development" },
    ];

    const socialMedias = [
        {
            id: 1,
            link: "https://dribbble.com/albert111198",
            logo: "logo-dribbble",
        },
        {
            id: 2,
            link: "https://www.instagram.com/yohanes_albert/",
            logo: "logo-instagram",
        },
        {
            id: 3,
            link: "https://www.linkedin.com/in/yohanes-albert/",
            logo: "logo-linkedin",
        },
        {
            id: 4,
            link: "https://github.com/albertofcyber98",
            logo: "logo-github",
        },
    ];

    return (
        <div>
            <Navbar />

            <div className="py-10 bg-white mt-[60px] md:mt-[80px] lg:mt-[100px] mx-[5%] md:mx-[15%] lg:mx-[20%] xl:mx-[25%] rounded hover:drop-shadow-[0_2px_6px_rgba(0,188,154,0.7)] transition-all duration-500">
                <h1 className="text-center text-3xl font-medium">
                    About Me
                </h1>

                <div className="flex flex-col lg:flex-row justify-between">
                    <div className="px-8 pt-5 text-[#2D2E37]">
                        <p>
                            I am from Indonesia and currently work as a
                            full-time freelancer. I am deeply interested in
                            technology, especially web development. The rapid
                            growth of technology motivates me to keep improving
                            my skills and building better digital products.
                        </p>

                        <p className="pt-3 pb-2 font-medium">
                            Services I offer:
                        </p>

                        {dataChecks.map((item) => (
                            <div className="flex" key={item.id}>
                                <div className="pt-[2px] text-[#00BC9A]">
                                    <ion-icon name="checkmark-circle-outline"></ion-icon>
                                </div>

                                <div className="pl-3">
                                    {item.title}
                                </div>
                            </div>
                        ))}
                    </div>

                    <div className="pr-5 pt-8 hidden lg:block">
                        <img
                            src={profil}
                            className="w-full"
                            alt="Profile"
                        />
                    </div>
                </div>
            </div>

            <div className="text-2xl text-center mt-10 flex justify-center gap-10">
                {socialMedias.map((socialMedia) => (
                    <a
                        key={socialMedia.id}
                        target="_blank"
                        rel="noreferrer"
                        href={socialMedia.link}
                        className="text-gray-400 hover:text-gray-600 transition-all duration-300"
                    >
                        <ion-icon name={socialMedia.logo}></ion-icon>
                    </a>
                ))}
            </div>
        </div>
    );
};

export default About;
